
const msgpack = (() => {
    const td = new TextDecoder();

    function decode(buf) {
        const u8 = buf instanceof Uint8Array ? buf : new Uint8Array(buf);
        const dv = new DataView(u8.buffer, u8.byteOffset, u8.byteLength);
        let p = 0;

        const ru8  = () => u8[p++];
        const ru16 = () => { const v = dv.getUint16(p); p += 2; return v; };
        const ru32 = () => { const v = dv.getUint32(p); p += 4; return v; };
        const ri8  = () => { const v = dv.getInt8(p);  p++;    return v; };
        const ri16 = () => { const v = dv.getInt16(p); p += 2; return v; };
        const ri32 = () => { const v = dv.getInt32(p); p += 4; return v; };
        const rf32 = () => { const v = dv.getFloat32(p); p += 4; return v; };
        const rf64 = () => { const v = dv.getFloat64(p); p += 8; return v; };

        const rstr = (len) => { const s = td.decode(u8.subarray(p, p + len)); p += len; return s; };
        const rbin = (len) => { const b = u8.slice(p, p + len); p += len; return b; };

        const rarr = (len) => { const a = new Array(len); for (let i = 0; i < len; i++) a[i] = rv(); return a; };
        const rmap = (len) => {
            const o = Object.create(null);
            for (let i = 0; i < len; i++) { const k = rv(); o[k] = rv(); }
            return o;
        };

        function rv() {
            const b = ru8();
            if (b <= 0x7f) return b;
            if (b >= 0xe0) return b - 256;
            const hi4 = b & 0xf0;
            if (hi4 === 0x80) return rmap(b & 0x0f);
            if (hi4 === 0x90) return rarr(b & 0x0f);
            if ((b & 0xe0) === 0xa0) return rstr(b & 0x1f);
            switch (b) {
                case 0xc0: return null;
                case 0xc2: return false;
                case 0xc3: return true;
                case 0xc4: return rbin(ru8());
                case 0xc5: return rbin(ru16());
                case 0xc6: return rbin(ru32());
                case 0xca: return rf32();
                case 0xcb: return rf64();
                case 0xcc: return ru8();
                case 0xcd: return ru16();
                case 0xce: return ru32();
                case 0xcf: { const hi = ru32(), lo = ru32(); return hi * 0x100000000 + lo; }
                case 0xd0: return ri8();
                case 0xd1: return ri16();
                case 0xd2: return ri32();
                case 0xd3: { const hi = ri32(), lo = ru32(); return hi * 0x100000000 + lo; }
                case 0xd9: return rstr(ru8());
                case 0xda: return rstr(ru16());
                case 0xdb: return rstr(ru32());
                case 0xdc: return rarr(ru16());
                case 0xdd: return rarr(ru32());
                case 0xde: return rmap(ru16());
                case 0xdf: return rmap(ru32());
                default: throw new Error("Unknown msgpack byte: 0x" + b.toString(16));
            }
        }
        return rv();
    }
    return { decode };
})();

async function decompressGzip(buffer) {
    const ds = new DecompressionStream('gzip');
    const writer = ds.writable.getWriter();
    writer.write(buffer);
    writer.close();

    const chunks = [];
    const reader = ds.readable.getReader();
    let totalLen = 0;
    while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        chunks.push(value);
        totalLen += value.length;
    }

    const out = new Uint8Array(totalLen);
    let offset = 0;
    for (const chunk of chunks) {
        out.set(chunk, offset);
        offset += chunk.length;
    }
    return out;
}

onmessage = async function(e) {
    try {
        const buffer = e.data;
        const decompressed = await decompressGzip(buffer);
        const data = msgpack.decode(decompressed);
        postMessage({ success: true, data }, []); 
    } catch (err) {
        postMessage({ success: false, error: err.message });
    }
};
